6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill single cell due to underpopulation", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should keep live cell with 2 neighbors", () => {
12	    expect(nextGeneration([[0, 0], [-1, 0], [1, 0]])).toEqual([[0, 0]]);
13	  });
