15	    expect(nextGeneration([[0, 0], [-1, 0], [1, 0], [0, 1]])).toEqual([[0, 0]]);
16	  });
17	  it("should kill live cell with 1 neighbor", () => {
18	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
19	  });
20	  it("should kill live cell with 4 neighbors", () => {
21	    expect(nextGeneration([[0, 0], [-1, 0], [1, 0], [0, -1], [0, 1]])).toEqual([]);
22	  });
23	  it("should resurrect dead cell with exactly 3 neighbors", () => {
24	    expect(nextGeneration([[-1, 0], [1, 0], [0, -1]])).toEqual([[0, 0]]);
