1	const countLiveOrthogonalNeighbors = (
2	  x: number,
3	  y: number,
4	  liveCells: Set<string>
5	): number => {
6	  let neighbors = 0;
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      if (dx !== 0 && dy !== 0) continue;
11	      if (liveCells.has(`${x + dx},${y + dy}`)) {
12	        neighbors++;
13	      }
14	    }
15	  }
16	  return neighbors;
17	};
