19	export function nextGeneration(grid: Array<[number, number]>): Array<[number, number]> {
20	  const survivors: Array<[number, number]> = [];
21	  const liveCells = new Set(grid.map(([x, y]) => `${x},${y}`));
22	  const births: Array<[number, number]> = [];
23	  const deadCellsToCheck = new Set<string>();
24	
25	  // Check survivors and collect dead cells around them
26	  for (const [x, y] of grid) {
27	    const neighborCount = countLiveOrthogonalNeighbors(x, y, liveCells);
28	
29	    if (neighborCount === 2 || neighborCount === 3) {
30	      survivors.push([x, y]);
31	    }
32	
33	    // Add dead neighbors to check for birth
34	    for (let dx = -1; dx <= 1; dx++) {
35	      for (let dy = -1; dy <= 1; dy++) {
36	        if (dx === 0 && dy === 0) continue;
37	        if (dx !== 0 && dy !== 0) continue;
38	        const nx = x + dx;
39	        const ny = y + dy;
40	        if (!liveCells.has(`${nx},${ny}`)) {
41	          deadCellsToCheck.add(`${nx},${ny}`);
42	        }
43	      }
44	    }
45	  }
46	
47	  // Check dead cells for birth
48	  for (const cellStr of deadCellsToCheck) {
49	    const [xStr, yStr] = cellStr.split(",");
50	    const x = parseInt(xStr);
51	    const y = parseInt(yStr);
52	    const neighborCount = countLiveOrthogonalNeighbors(x, y, liveCells);
53	    if (neighborCount === 3) {
54	      births.push([x, y]);
55	    }
56	  }
57	
58	  return [...survivors, ...births];
59	}
60	

